func solve(n int64, edges [][]int64, k int64) int64 {
    low := int64(0)
    high := int64(1000000)

    for low <= high {
        mid := (low + high) / 2
        nInt := int(n)
        parent := make([]int, nInt)
        rank := make([]int, nInt)
        comps := nInt

        for i := 0; i < nInt; i++ {
            parent[i] = i
        }

        find := func(x int) int {
            r := x
            for r != parent[r] {
                r = parent[r]
            }
            temp := x
            for temp != r {
                next := parent[temp]
                parent[temp] = r
                temp = next
            }
            return r
        }

        union := func(x, y int) {
            rx := find(x)
            ry := find(y)
            if rx == ry {
                return
            }
            if rank[rx] < rank[ry] {
                rx, ry = ry, rx
            }
            if rank[rx] == rank[ry] {
                rank[rx]++
            }
            parent[ry] = rx
            comps--
        }

        for _, edge := range edges {
            u, v, w := edge[0], edge[1], edge[2]
            if w <= mid {
                uInt, vInt := int(u), int(v)
                union(uInt, vInt)
            }
        }

        if int64(comps) <= k {
            high = mid - 1
        } else {
            low = mid + 1
        }
    }

    return low
}
